patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..efc05a0e57d7 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1898,6 +1898,45 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      if (auto *II = dyn_cast<IntrinsicInst>(CB.Inst)) {
+        switch (II->getIntrinsicID()) {
+        case Intrinsic::usub_sat:
+          // usub_sat(x, y) <= x
+          AddFact(CmpInst::ICMP_UGE, II->getArgOperand(0), II);
+          // usub_sat(x, y) >= 0
+          AddFact(CmpInst::ICMP_UGE, II,
+                  ConstantInt::get(II->getType(), 0));
+          continue;
+        case Intrinsic::uadd_sat:
+          // uadd_sat(x, y) >= x
+          AddFact(CmpInst::ICMP_UGE, II, II->getArgOperand(0));
+          // uadd_sat(x, y) >= y
+          AddFact(CmpInst::ICMP_UGE, II, II->getArgOperand(1));
+          // uadd_sat(x, y) <= -1 (all ones)
+          AddFact(CmpInst::ICMP_ULE, II,
+                  ConstantInt::getAllOnesValue(II->getType()));
+          continue;
+        case Intrinsic::ssub_sat:
+          // ssub_sat(x, y) <= x (signed)
+          AddFact(CmpInst::ICMP_SGE, II->getArgOperand(0), II);
+          // ssub_sat(x, y) >= INT_MIN
+          AddFact(CmpInst::ICMP_SGE, II,
+                  ConstantInt::get(II->getContext(), APInt::getSignedMinValue(II->getType()->getScalarSizeInBits())));
+          continue;
+        case Intrinsic::sadd_sat:
+          // sadd_sat(x, y) >= x (signed)
+          AddFact(CmpInst::ICMP_SGE, II, II->getArgOperand(0));
+          // sadd_sat(x, y) >= y
+          AddFact(CmpInst::ICMP_SGE, II, II->getArgOperand(1));
+          // sadd_sat(x, y) <= INT_MAX
+          AddFact(CmpInst::ICMP_SLE, II,
+                  ConstantInt::get(II->getContext(), APInt::getSignedMaxValue(II->getType()->getScalarSizeInBits())));
+          continue;
+        default:
+          break;
+        }
+      }
     }

     Value *A = nullptr, *B = nullptr;

